import{_ as d}from"./chunks/god-mod-relics.BYI1kHif.js";import{_ as t,a as o}from"./chunks/god-mod-cards.BwnlzbNn.js";import{_ as e,o as r,c as h,ag as i,j as l}from"./chunks/framework.DjqkqlVQ.js";const q=JSON.parse('{"title":"STS2 God Mod","description":"","frontmatter":{},"headers":[],"relativePath":"mods/sts2-god-mod/index.md","filePath":"mods/sts2-god-mod/index.md","lastUpdated":1778862993000}'),s={name:"mods/sts2-god-mod/index.md"};function n(c,a,p,u,b,m){return r(),h("div",null,[...a[0]||(a[0]=[i('<h1 id="sts2-god-mod" tabindex="-1">STS2 God Mod <a class="header-anchor" href="#sts2-god-mod" aria-label="Permalink to &quot;STS2 God Mod&quot;">​</a></h1><p>God Mod 是一个面向 杀戮尖塔2 的工具型 / 作弊型 Mod，主要用于测试、沙盒玩法、构筑实验和快速起局。它提供一组强力工具，让玩家和 Mod 作者可以直接修改游戏状态，跳过重复准备流程，更快验证想法。</p><p>当前版本：<code>1.6.1</code><br> 作者：Jason Song<br> 类型：沙盒工具 / 测试工具 / 作弊型 Mod<br> 是否影响玩法：是。它会主动修改游戏状态，建议在明确需要测试或沙盒体验时使用。</p><h2 id="本版要点-v1-6-1" tabindex="-1">本版要点（v1.6.1） <a class="header-anchor" href="#本版要点-v1-6-1" aria-label="Permalink to &quot;本版要点（v1.6.1）&quot;">​</a></h2><ul><li>正式版兼容性修复。</li></ul><h2 id="截图" tabindex="-1">截图 <a class="header-anchor" href="#截图" aria-label="Permalink to &quot;截图&quot;">​</a></h2><div class="screenshot-grid"><figure><img src="'+d+'" alt="God Mod 遗物管理界面"><figcaption>遗物管理与快速添加。</figcaption></figure><figure><img src="'+t+'" alt="God Mod 控制台界面"><figcaption>G 面板工具入口。</figcaption></figure><figure><img src="'+o+'" alt="God Mod 卡牌管理界面"><figcaption>卡牌管理与构筑测试。</figcaption></figure></div><h2 id="适合谁使用" tabindex="-1">适合谁使用 <a class="header-anchor" href="#适合谁使用" aria-label="Permalink to &quot;适合谁使用&quot;">​</a></h2><ul><li>想快速测试卡组、遗物、药水或状态组合的玩家。</li><li>做 杀戮尖塔2 Mod 时需要反复验证机制的人。</li><li>想跳过重复开局、直接进入特定实验场景的人。</li><li>需要调试事件、战斗、地图或多人同步行为的开发者。</li></ul><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><ul><li>编辑金币、当前生命值、最大生命值、能量和药水槽。</li><li>添加或删除遗物，并支持快捷遗物组合。</li><li>添加、删除、复制、变化、升级、降级、附魔、关键词编辑和数值编辑卡牌。</li><li>保存并应用自定义卡组预设。</li><li>按职业使用内置无限卡组预设。</li><li>添加药水、补满空药水槽或清空药水。</li><li>在战斗中添加或移除状态。</li><li>使用战斗快捷功能，例如满血、满能量、清除减益、击杀全部敌人，以及抽牌 / 弃牌控制。</li><li>在战斗中生成敌人。</li><li>在跑图过程中直接进入指定事件。</li><li>启用火堆辅助，例如一次敲两张牌，以及每个火堆额外删 1 张牌。</li><li>通过悬浮 <code>G</code> 按钮或长按 <code>G</code> 快捷键打开面板。</li></ul><h2 id="主要工具区" tabindex="-1">主要工具区 <a class="header-anchor" href="#主要工具区" aria-label="Permalink to &quot;主要工具区&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具区</th><th>能做什么</th></tr></thead><tbody><tr><td>资源编辑</td><td>修改金币、生命、能量、药水槽等基础状态</td></tr><tr><td>遗物管理</td><td>添加、删除遗物，快速套用遗物组合</td></tr><tr><td>卡牌管理</td><td>添加、复制、变化、升级、降级、附魔和编辑卡牌</td></tr><tr><td>卡组预设</td><td>保存和应用自定义卡组，快速复现测试场景</td></tr><tr><td>药水工具</td><td>添加、补满或清空药水</td></tr><tr><td>战斗工具</td><td>调整状态，满血满能量，清除减益，击杀敌人，控制抽弃牌</td></tr><tr><td>事件工具</td><td>在跑图中进入指定事件，辅助事件测试</td></tr><tr><td>火堆辅助</td><td>双敲、额外删牌等测试向流程加速</td></tr></tbody></table><h2 id="打开方式" tabindex="-1">打开方式 <a class="header-anchor" href="#打开方式" aria-label="Permalink to &quot;打开方式&quot;">​</a></h2><ul><li>点击游戏内悬浮 <code>G</code> 按钮。</li><li>或长按 <code>G</code> 快捷键打开面板。</li></ul><h2 id="安装说明" tabindex="-1">安装说明 <a class="header-anchor" href="#安装说明" aria-label="Permalink to &quot;安装说明&quot;">​</a></h2><ol><li>下载发布包。</li><li>解压压缩包。</li><li>将 Mod 文件放入 杀戮尖塔2 的 Mod 文件夹： <ul><li>Windows：<code>mods/</code></li><li>macOS：<code>SlayTheSpire2.app/Contents/MacOS/mods/</code></li></ul></li><li>启动游戏，并在需要时启用该 Mod。</li></ol><p>发布包通常会包含 <code>.dll</code>、<code>.pck</code> 和 manifest 文件。</p><h2 id="视频演示" tabindex="-1">视频演示 <a class="header-anchor" href="#视频演示" aria-label="Permalink to &quot;视频演示&quot;">​</a></h2><p>【杀戮尖塔2】God Mod 控制台</p>',20),l("div",{class:"video-embed"},[l("iframe",{src:"https://player.bilibili.com/player.html?bvid=BV1fJXLBuERb&page=1",title:"【杀戮尖塔2】God Mod 控制台",scrolling:"no",border:"0",frameborder:"no",framespacing:"0",allowfullscreen:"true"})],-1),i('<h2 id="兼容性说明" tabindex="-1">兼容性说明 <a class="header-anchor" href="#兼容性说明" aria-label="Permalink to &quot;兼容性说明&quot;">​</a></h2><p>God Mod 会直接修改核心游戏状态。如果同时使用其他修改核心玩法、UI、调试系统或多人同步行为的 Mod，可能会出现兼容性问题。</p><p>最推荐的使用方式：</p><ul><li>单人测试、沙盒玩法、构筑实验和快速起局。</li><li>联机测试时，所有玩家都安装同一个版本的 God Mod，并且都明确同意本局用于测试。</li></ul><p>不推荐把 God Mod 当作普通联机局的常规辅助工具。它会改动大量本局状态；即使界面上能点，也不代表适合在公开联机、正常爬塔或不同 Mod 环境中使用。</p><p>God Mod 会优先维护稳定版游戏下的使用体验。Beta 版本、实验分支或游戏刚更新后的版本可能改动内部节点、同步逻辑或调试接口，因此不保证所有功能都能立即兼容。</p><h3 id="联机混装模式是什么" tabindex="-1">联机混装模式是什么 <a class="header-anchor" href="#联机混装模式是什么" aria-label="Permalink to &quot;联机混装模式是什么&quot;">​</a></h3><p>“混装模式”指的是联机房间里并非所有玩家都安装了同版本 God Mod，例如：</p><ul><li>房主没装 God Mod，加入方装了 God Mod。</li><li>有人装了 God Mod，有人没装。</li><li>多名玩家都装了 God Mod，但版本不一致。</li><li>打开了“放宽联机大厅对混装 mod 的检查”，让这些不完全一致的 Mod 环境更容易进入同一个房间。</li></ul><p>混装模式的目标只是降低进房门槛，并尽量保留少量相对安全、可通过游戏原生联机命令同步的工具。它不等于完整联机支持，也不保证所有 God Mod 功能都能正常使用。</p><p>如果你需要完整功能，优先使用单机，或者让所有玩家安装同一个版本的 God Mod。混装模式下遇到不同步、断线、表现不一致、房间卡住或崩溃，都属于已知风险范围。</p><h3 id="两个联机相关开关" tabindex="-1">两个联机相关开关 <a class="header-anchor" href="#两个联机相关开关" aria-label="Permalink to &quot;两个联机相关开关&quot;">​</a></h3><p>God Mod 里有两个容易混淆、但作用完全不同的联机开关：</p><table tabindex="0"><thead><tr><th>开关</th><th>作用</th><th>风险</th></tr></thead><tbody><tr><td>放宽联机大厅对混装 mod 的检查</td><td>让 God Mod 在联机大厅的基础 Mod 检查里不再按强 gameplay-affecting Mod 处理，从而更容易进入房主和加入方 Mod 环境不完全一致的房间。</td><td>只影响进房 / 大厅检查，不保证进入房间后功能安全。混装后使用会改游戏状态的功能，仍可能不同步、断线或崩溃。</td></tr><tr><td>专家模式：放开混装联机限制</td><td>在已经处于混装联机场景时，临时关闭 God Mod 对高风险功能的安全拦截。</td><td>这是危险覆盖开关，不是兼容保证。开启后，原本被限制的功能可能可以尝试点击，但任何状态改动都可能让多人局不同步、坏档或崩溃。</td></tr></tbody></table><p>简单说：大厅兼容开关解决的是“能不能更容易进房”；专家模式解决的是“要不要强行尝试那些默认被拦下的高风险功能”。两者都不是稳定联机保证。最稳妥的方式仍然是单机使用，或所有玩家安装同版本 God Mod。</p><h3 id="混装模式下默认保留的功能" tabindex="-1">混装模式下默认保留的功能 <a class="header-anchor" href="#混装模式下默认保留的功能" aria-label="Permalink to &quot;混装模式下默认保留的功能&quot;">​</a></h3><p>这些功能会尽量走较保守的同步路径，通常是混装模式下优先保留的功能：</p><ul><li>金币：只支持增加，不支持调低。</li><li>战斗能量：只支持增加，包括回满能量。</li><li>辉星：只支持增加。</li><li>回满血。</li><li>抽牌。</li><li>秒杀全部敌人。</li><li>遗物：添加、移除，以及补齐预设中缺少的遗物。</li><li>药水：添加药水。</li><li>事件跳转：通过原生事件命令进入事件；混装模式下事件列表会更保守。</li><li>卡牌管理： <ul><li>战斗中只支持操作手牌。</li><li>战斗中支持添加手牌、删除手牌、升级手牌、给手牌附魔。</li><li>非战斗中主要支持牌库操作，例如添加普通牌到牌库、从牌库删牌、升级牌库里的牌。</li></ul></li></ul><h3 id="混装模式下不保证可用的功能" tabindex="-1">混装模式下不保证可用的功能 <a class="header-anchor" href="#混装模式下不保证可用的功能" aria-label="Permalink to &quot;混装模式下不保证可用的功能&quot;">​</a></h3><p>下面这些功能依赖 God Mod 自定义同步，或更容易导致多人状态分叉。混装模式下默认会被限制；如果你临时打开专家模式，需要自己确认风险并在用完后尽快关闭。</p><ul><li>精确调低金币、能量或辉星。</li><li>修改当前生命、最大生命、最大能量、药水槽数量。</li><li>先古相关增强，例如刷新选项、修改展示数量、先古保存 / 读取辅助。</li><li>火堆增强，例如双重锻造、额外免费删牌。</li><li>卡组预设、清空牌组、替换牌组、无限牌组预设。</li><li>卡牌高级编辑，例如降级、复制、变化、清诅咒、修改费用 / 伤害 / 格挡 / 魔法值、额外动作、清除附魔、添加或移除关键词。</li><li>操作抽牌堆、弃牌堆、消耗堆，或在混装限制外执行非手牌卡牌操作。</li><li>药水高级操作，例如清空药水、移除指定药水、填满药水槽。</li><li>战斗状态和敌人相关高级操作，例如生成敌人、设置敌人生命、添加或移除能力、清除减益、指定弃牌。</li><li>Traveler 模式：真实多人中会直接禁用。</li></ul><p>“专家模式：放开混装联机限制”是高风险覆盖开关。它的作用是减少 God Mod 对混装联机的安全拦截，不是保证这些功能可以稳定同步。开启后，任何会改变游戏状态的操作都可能造成不同步、断线、坏档或崩溃；每次新开一局时它会自动重置为关闭。</p><p>遇到不同步、断线或表现不一致时，可以附上游戏版本、God Mod 版本、是否混装、房主 / 加入方情况、是否开启专家模式和复现步骤。</p><h2 id="后续路线图" tabindex="-1">后续路线图 <a class="header-anchor" href="#后续路线图" aria-label="Permalink to &quot;后续路线图&quot;">​</a></h2><p>后续会继续围绕测试效率、沙盒体验和兼容性做改进，包括翻译质量维护、更清晰的面板说明、更稳定的多人测试体验，以及更方便的预设和构筑复现流程。</p><h2 id="链接" tabindex="-1">链接 <a class="header-anchor" href="#链接" aria-label="Permalink to &quot;链接&quot;">​</a></h2><ul><li>夸克下载：<a href="https://pan.quark.cn/s/2c8c2850621d" target="_blank" rel="noreferrer">pan.quark.cn/s/2c8c2850621d</a></li><li>Nexus Mods: <a href="https://www.nexusmods.com/slaythespire2/mods/304" target="_blank" rel="noreferrer">杀戮尖塔2 Mod #304</a></li><li>视频演示：<a href="https://www.bilibili.com/video/BV1fJXLBuERb" target="_blank" rel="noreferrer">Bilibili BV1fJXLBuERb</a></li></ul><h2 id="使用提醒" tabindex="-1">使用提醒 <a class="header-anchor" href="#使用提醒" aria-label="Permalink to &quot;使用提醒&quot;">​</a></h2><p>这个 Mod 是测试和沙盒工具，不适合用来衡量正常流程强度。如果你想保留原版成长体验，建议只在独立存档、测试环境或明确的实验流程中使用。</p>',29)])])}const g=e(s,[["render",n]]);export{q as __pageData,g as default};
